          pdvCsvRows=raw.slice(1).filter(r=>r.some(c=>c)).map(r=>{
            const o={}; headerRow.forEach((h,i)=>{ o[h.toLowerCase().trim()]=r[i]??''; }); return o;
          });
          document.getElementById('pdvDetectedCols').textContent=headers.join(', ')||'—';
          const rowErrors=[];
