  // FIX D-1 (Efetividade) â€” normaliza Date vindo de ISO YYYY-MM-DD (UTC midnight) para dia local correto (evita D-2)
  (function(){
    try{
      if(!/Efetividade/i.test(document.title||"")) return;

      function normalizeRefDate(d){
        try{
          if(!(d instanceof Date) || !isFinite(d.getTime())) return new Date();
          const isUtcMidnight = (d.getUTCHours()===0 && d.getUTCMinutes()===0 && d.getUTCSeconds()===0 && d.getUTCMilliseconds()===0);
          const isWhole = (d.getMinutes()===0 && d.getSeconds()===0 && d.getMilliseconds()===0);
          if(isUtcMidnight && isWhole){
            // Se foi criado por new Date("YYYY-MM-DD"), em fuso negativo vira D-2. Corrige usando componentes UTC.
            return new Date(d.getUTCFullYear(), d.getUTCMonth(), d.getUTCDate());
          }
          // Caso geral: zera horÃ¡rio e mantÃ©m o dia local.
          return new Date(d.getFullYear(), d.getMonth(), d.getDate());
        }catch(_e){ return new Date(); }
      }
      function fmt(d){
        try{
          if(typeof window.fmtBrDate==="function") return window.fmtBrDate(d);
        }catch(_e){}
        const dd = String(d.getDate()).padStart(2,"0");
        const mm = String(d.getMonth()+1).padStart(2,"0");
        const yy = d.getFullYear();
        return dd+"/"+mm+"/"+yy;
      }
      function add(d, n){
        try{
          if(typeof window.addDays==="function") return window.addDays(d, n);
        }catch(_e){}
        return new Date(d.getFullYear(), d.getMonth(), d.getDate()+n);
      }
      function patch(){
        if(typeof window.computeD1Targets!=="function") return false;
        if(window.computeD1Targets && window.computeD1Targets.__ciaPatchedD1) return true;

        const orig = window.computeD1Targets;
        window.computeD1Targets = function(refDate){
          try{
            const baseIn = (refDate instanceof Date) ? refDate : (refDate ? new Date(refDate) : new Date());
            const base = normalizeRefDate(baseIn);
            const today = isFinite(base.getTime()) ? base : new Date();

            if(today.getDay()===1){ // segunda
              const fri = add(today, -3);
              const sat = add(today, -2);
              return [fmt(fri), fmt(sat)];
            }
            const y = add(today, -1);
            return [fmt(y)];
          }catch(_e){
            try{ return orig(refDate); }catch(_e2){ return []; }
          }
        };
        window.computeD1Targets.__ciaPatchedD1 = true;
        return true;
      }

      // tenta agora e re-tenta em curto perÃ­odo (caso a ordem de scripts mude)
      if(!patch()){
        let tries = 0;
        const t = setInterval(()=>{
          tries++;
          if(patch() || tries>40) clearInterval(t);
        }, 50);
      }
    }catch(_e){}
  })();


